import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import logo from '../assets/logo.png';

export default function AuthPage() {
  const navigate = useNavigate();
  const [mode, setMode] = useState('login'); // 'login' | 'signup' | 'forgot'
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState('');
  const [errors, setErrors] = useState({});

  const [form, setForm] = useState({
    name: '', email: '', phone: '', password: '', confirmPassword: '',
  });

  const update = (field, value) => {
    setForm(f => ({ ...f, [field]: value }));
    setErrors(e => ({ ...e, [field]: '' }));
  };

  const validate = () => {
    const e = {};
    if (mode === 'signup' && !form.name.trim()) e.name = 'Name is required';
    if (!form.email.match(/^[^\s@]+@[^\s@]+\.[^\s@]+$/)) e.email = 'Valid email required';
    if (mode === 'signup' && !form.phone.match(/^[6-9]\d{9}$/)) e.phone = 'Valid 10-digit mobile required';
    if (mode !== 'forgot' && form.password.length < 6) e.password = 'Password must be at least 6 characters';
    if (mode === 'signup' && form.password !== form.confirmPassword) e.confirmPassword = 'Passwords do not match';
    return e;
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const e2 = validate();
    if (Object.keys(e2).length > 0) { setErrors(e2); return; }
    setLoading(true);
    setTimeout(() => {
      setLoading(false);
      if (mode === 'forgot') {
        setSuccess('Password reset link sent to your email!');
      } else {
        navigate('/');
      }
    }, 1600);
  };

  const Field = ({ label, field, type = 'text', placeholder }) => (
    <div>
      <label className="text-xs font-semibold text-gray-500 block mb-1.5">{label}</label>
      <input
        type={type}
        value={form[field]}
        onChange={e => update(field, e.target.value)}
        placeholder={placeholder}
        className={`w-full border rounded-xl px-4 py-3 text-sm outline-none transition-colors
          ${errors[field] ? 'border-red-400 bg-red-50' : 'border-gray-200 focus:border-ink bg-white'}`}
      />
      {errors[field] && <p className="text-red-500 text-xs mt-1">{errors[field]}</p>}
    </div>
  );

  return (
    <div className="min-h-screen bg-gray-50 flex items-center justify-center px-4 py-12">
      <div className="w-full max-w-md">

        {/* Logo */}
        <div className="flex flex-col items-center mb-8">
          <img
            src={logo}
            alt="AnimeMonkey"
            className="h-20 w-auto object-contain mb-3 cursor-pointer"
            style={{ filter: 'drop-shadow(0 4px 12px rgba(0,0,0,0.15))' }}
            onClick={() => navigate('/')}
          />
          <h1 className="text-xl font-bold text-ink" style={{ fontFamily: 'Playfair Display, serif' }}>
            {mode === 'login' ? 'Welcome back!' : mode === 'signup' ? 'Create your account' : 'Reset password'}
          </h1>
          <p className="text-sm text-gray-400 mt-1">
            {mode === 'login' ? 'Sign in to track orders & manage wishlist' :
             mode === 'signup' ? 'Join the AnimeMonkey family 🐵' :
             'We\'ll send you a reset link'}
          </p>
        </div>

        {/* Card */}
        <div className="bg-white rounded-3xl shadow-sm p-8">

          {/* Success message */}
          {success && (
            <div className="bg-green-50 border border-green-200 rounded-xl px-4 py-3 mb-5 flex items-center gap-3">
              <span className="text-green-500 text-lg">✓</span>
              <p className="text-sm text-green-700 font-medium">{success}</p>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-4">

            {/* Signup only — Name */}
            {mode === 'signup' && (
              <Field label="Full Name *" field="name" placeholder="Rahul Sharma" />
            )}

            {/* Email */}
            <Field label="Email Address *" field="email" type="email" placeholder="rahul@email.com" />

            {/* Signup only — Phone */}
            {mode === 'signup' && (
              <Field label="Mobile Number *" field="phone" placeholder="9876543210" />
            )}

            {/* Password */}
            {mode !== 'forgot' && (
              <Field label="Password *" field="password" type="password" placeholder="Min. 6 characters" />
            )}

            {/* Signup only — Confirm Password */}
            {mode === 'signup' && (
              <Field label="Confirm Password *" field="confirmPassword" type="password" placeholder="Repeat password" />
            )}

            {/* Forgot password link */}
            {mode === 'login' && (
              <div className="flex justify-end">
                <button
                  type="button"
                  onClick={() => { setMode('forgot'); setErrors({}); setSuccess(''); }}
                  className="text-xs text-gray-400 hover:text-ink transition-colors"
                >
                  Forgot password?
                </button>
              </div>
            )}

            {/* Submit button */}
            <button
              type="submit"
              disabled={loading}
              className="w-full bg-ink text-white py-3.5 rounded-xl text-sm font-bold hover:bg-gray-800 transition-colors disabled:opacity-60 flex items-center justify-center gap-2 mt-2"
            >
              {loading ? (
                <>
                  <svg className="animate-spin w-4 h-4" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8v8H4z" />
                  </svg>
                  {mode === 'login' ? 'Signing in...' : mode === 'signup' ? 'Creating account...' : 'Sending...'}
                </>
              ) : (
                mode === 'login' ? 'Sign In' : mode === 'signup' ? 'Create Account' : 'Send Reset Link'
              )}
            </button>

            {/* OR divider */}
            {mode !== 'forgot' && (
              <>
                <div className="flex items-center gap-3 my-2">
                  <div className="flex-1 h-px bg-gray-100" />
                  <span className="text-xs text-gray-400">or continue with</span>
                  <div className="flex-1 h-px bg-gray-100" />
                </div>

                {/* Google sign in */}
                <button
                  type="button"
                  className="w-full flex items-center justify-center gap-3 border border-gray-200 rounded-xl py-3 text-sm font-semibold text-gray-600 hover:border-gray-400 hover:bg-gray-50 transition-all"
                >
                  <svg className="w-4 h-4" viewBox="0 0 24 24">
                    <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z"/>
                    <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z"/>
                    <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z"/>
                    <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z"/>
                  </svg>
                  Continue with Google
                </button>
              </>
            )}

          </form>
        </div>

        {/* Switch mode */}
        <div className="text-center mt-5 space-y-2">
          {mode === 'login' && (
            <p className="text-sm text-gray-400">
              Don't have an account?{' '}
              <button onClick={() => { setMode('signup'); setErrors({}); setSuccess(''); }}
                className="text-ink font-bold hover:underline">
                Sign up
              </button>
            </p>
          )}
          {mode === 'signup' && (
            <p className="text-sm text-gray-400">
              Already have an account?{' '}
              <button onClick={() => { setMode('login'); setErrors({}); setSuccess(''); }}
                className="text-ink font-bold hover:underline">
                Sign in
              </button>
            </p>
          )}
          {mode === 'forgot' && (
            <p className="text-sm text-gray-400">
              Remember it?{' '}
              <button onClick={() => { setMode('login'); setErrors({}); setSuccess(''); }}
                className="text-ink font-bold hover:underline">
                Back to Sign in
              </button>
            </p>
          )}
          <p className="text-xs text-gray-300">
            By continuing you agree to our Terms & Privacy Policy
          </p>
        </div>

      </div>
    </div>
  );
}
